(game "Tacky Quokka Of Peace"
    (players 2)
    (equipment
        (board (square 5))
    )
    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination empty)
                    (effects
                        (capture (custodial ANY orientation:orthogonal))
                    )
                )
            )
        )
        (end
            (if (and
                (mover_is P1)
                (exists (and
                    (pattern (2 2) (1 1 1 1))
                    (adjacent (prev_move mover) orthogonal)  // New den contains last move
                ))
                (not (exists (and
                    (adjacent
                        (and (pattern (2 2) (1 1 1 1)) (adjacent (prev_move mover) orthogonal))
                        orthogonal
                    )
                    (occupied P2)
                )))
            ) (mover win))

            (if (and
                (mover_is P2)
                (exists (and
                    (pattern (2 2) (2 2 2 2))
                    (adjacent (prev_move mover) orthogonal)
                ))
                (not (exists (and
                    (adjacent
                        (and (pattern (2 2) (2 2 2 2)) (adjacent (prev_move mover) orthogonal))
                        orthogonal
                    )
                    (occupied P1)
                )))
            ) (mover win))

            (if (full_board) (draw))
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

